import { FlairDefinition, GraphQLDefinition, HTTPDefinition, KVStoreDefinition, LinksAndCommentsDefinition, ListingsDefinition, LoggerDefinition, MediaServiceDefinition, ModerationDefinition, ModNoteDefinition, NewModmailDefinition, PrivateMessagesDefinition, RealtimeDefinition, RedisAPIDefinition, SchedulerDefinition, SettingsDefinition, SubredditsDefinition, TimerDefinition, UserActionsDefinition, UsersDefinition, WidgetsDefinition, WikiDefinition, } from '@devvit/protos';
import { AssetResolverDefinition, PostCollectionsDefinition, RedditAPIV2Definition, } from '@devvit/protos/lib/Defunct-Types.js';
import { Definition } from '@devvit/protos/lib/Types.js';
import { PaymentsServiceDefinition } from '@devvit/protos/payments.js';
import { WrapperTypesDefinition } from '@devvit/protos/types/devvit/actor/test/wrappertypes.js';
import { BlobServiceDefinition } from '@devvit/protos/types/devvit/plugin/blob/v1alpha/blob.js';
import { ClockDefinition } from '@devvit/protos/types/devvit/plugin/clock/clock.js';
import { LOCAL_HOSTNAME, resolvePluginDefinitionHostname, resolveSystemHostname, } from '@devvit/shared-types/HostnameUtil.js';
import { InMemoryResolver } from './resolver.js';
// An in-memory resolver implementation, with Devvit's known plugins (real and test)
// automatically registered.
// This is intended for easy use with DefaultBuilder.
export class ResolverWithPlugins extends InMemoryResolver {
    constructor() {
        super({
            descriptions: [
                BlobServiceDefinition,
                ClockDefinition,
                FlairDefinition,
                GraphQLDefinition,
                HTTPDefinition,
                KVStoreDefinition,
                LinksAndCommentsDefinition,
                ListingsDefinition,
                LoggerDefinition,
                MediaServiceDefinition,
                ModerationDefinition,
                ModNoteDefinition,
                NewModmailDefinition,
                PaymentsServiceDefinition,
                PrivateMessagesDefinition,
                RealtimeDefinition,
                RedisAPIDefinition,
                SchedulerDefinition,
                SettingsDefinition,
                SubredditsDefinition,
                TimerDefinition,
                UserActionsDefinition,
                UsersDefinition,
                WidgetsDefinition,
                WikiDefinition,
                WrapperTypesDefinition,
            ].map((pluginDef) => {
                // TODO: Clean up special handling https://reddit.atlassian.net/browse/DXC-115
                if (pluginDef.fullName.includes('.redditapi.')) {
                    return {
                        hostname: resolveSystemHostname(`redditapi`, { hostname: LOCAL_HOSTNAME }),
                        provides: [Definition.toSerializable(pluginDef)],
                    };
                }
                return {
                    hostname: resolvePluginDefinitionHostname(pluginDef, { hostname: LOCAL_HOSTNAME }),
                    provides: [Definition.toSerializable(pluginDef)],
                };
            }),
        }, 
        // Defunct packages. If packages are removed from the list above, their fully-qualified names
        // should be included here to avoid linker failures.
        [
            AssetResolverDefinition.fullName,
            PostCollectionsDefinition.fullName,
            RedditAPIV2Definition.fullName,
        ]);
    }
}
